from typing import Optional

def calculate_discount(price: float, discount_pct: float) -> Optional[float]:
    """Calculate discounted price. Returns None for invalid inputs."""
    if price < 0 or discount_pct < 0 or discount_pct > 100:
        return None
    return round(price * (1 - discount_pct / 100), 2)

